import json
import os
import boto3

s3 = boto3.client("s3")
dynamodb = boto3.resource("dynamodb")
sns = boto3.client("sns")
sqs = boto3.client("sqs")

TABLE_NAME = os.environ.get("TABLE_NAME", "your-table-name")
SNS_TOPIC_ARN = os.environ.get("SNS_TOPIC_ARN", "arn:aws:sns:us-east-1:123456789012:your-topic-name")
SQS_QUEUE_URL = os.environ.get("SQS_QUEUE_URL", "https://sqs.us-east-1.amazonaws.com/123456789012/your-queue-name")
S3_BUCKET = os.environ.get("S3_BUCKET", "your-shared-bucket")


def lambda_handler(event, context):
    table = dynamodb.Table(TABLE_NAME)

    item = {
        "requestId": context.aws_request_id,
        "eventType": event.get("type", "unknown"),
        "payload": event,
    }

    table.put_item(Item=item)

    sns.publish(
        TopicArn=SNS_TOPIC_ARN,
        Subject="Lambda Event Processed",
        Message=json.dumps({"requestId": context.aws_request_id, "status": "processed"}),
    )

    sqs.send_message(
        QueueUrl=SQS_QUEUE_URL,
        MessageBody=json.dumps({"requestId": context.aws_request_id, "source": "lambda"}),
    )

    s3.put_object(
        Bucket=S3_BUCKET,
        Key=f"events/{context.aws_request_id}.json",
        Body=json.dumps(event).encode("utf-8"),
        ContentType="application/json",
    )

    return {
        "statusCode": 200,
        "body": json.dumps(
            {
                "message": "Event processed successfully",
                "requestId": context.aws_request_id,
            }
        ),
    }